   # Raw API response shape — what data-manager actually returns
   class RegimeAPIResponse(BaseModel):
       pair: str
       metric: str
       data: RegimeAPIData
       metadata: RegimeAPIMetadata

   class RegimeAPIData(BaseModel):
       regime: RegimeEnum                    # "trending_bull" etc — matches framework
       volatility_level: VolatilityLevel     # "low|medium|high|extreme" — needs verification
       volume_level: str                     # not used by framework yet, keep as str
       trend_direction: str                  # not used by framework yet, keep as str
       confidence: str                       # "0.85" — string from API, needs conversion

   # Framework's internal representation — what the LLM and Code Engine see
   class RegimeResult(BaseModel):
       regime: RegimeEnum
       regime_confidence: ConfidenceLevel    # "high|medium|low" — converted from API string
       primary_signal: str
       thought_trace: str
   ```

